31	func (c *LRUCache) Put(key string, value interface{}) {
32		if elem, ok := c.items[key]; ok {
33			c.order.MoveToFront(elem)
34			elem.Value.(*entry).value = value
35			return
36		}
37		if c.order.Len() >= c.cap {
38			oldest := c.order.Back()
39			c.order.Remove(oldest)
40			delete(c.items, oldest.Value.(*entry).key)
41		}
42		elem := c.order.PushFront(&entry{key, value})
43		c.items[key] = elem
